class Solution:
    def findRotateSteps(self, ring, key):
        import sys
        n = len(ring)
        from functools import lru_cache
        sys.setrecursionlimit(10000)
        pos = {}
        for i, c in enumerate(ring):
            pos.setdefault(c, []).append(i)
        @lru_cache(None)
        def dp(ki, cur):
            if ki == len(key):
                return 0
            best = float('inf')
            for nxt in pos[key[ki]]:
                d = abs(cur - nxt)
                d = min(d, n - d)
                best = min(best, d + 1 + dp(ki + 1, nxt))
            return best
        return dp(0, 0)

