class Solution:
    def findRotateSteps(self, ring, key):
        n = len(ring)
        pos = {}
        for i, c in enumerate(ring):
            pos.setdefault(c, []).append(i)
        cur = {0: 0}
        for ch in key:
            nxt = {}
            for p in pos[ch]:
                best = float('inf')
                for cp, cost in cur.items():
                    d = abs(cp - p)
                    d = min(d, n - d)
                    best = min(best, cost + d + 1)
                nxt[p] = best
            cur = nxt
        return min(cur.values())

