var findRotateSteps = function(ring, key) {
    const n = ring.length;
    const pos = {};
    for (let i = 0; i < n; i++) {
        (pos[ring[i]] = pos[ring[i]] || []).push(i);
    }
    let cur = new Map([[0, 0]]);
    for (const ch of key) {
        const next = new Map();
        for (const p of pos[ch]) {
            let best = Infinity;
            for (const [cp, cost] of cur) {
                let d = Math.abs(cp - p);
                d = Math.min(d, n - d);
                best = Math.min(best, cost + d + 1);
            }
            next.set(p, best);
        }
        cur = next;
    }
    let ans = Infinity;
    for (const v of cur.values()) ans = Math.min(ans, v);
    return ans;
};
